select u.username user_name, u.avatar user_avatar, br.score, br.content, br.created_time from business_rating br left join user u on br.user_id = u.id
br.product_id = #{dto.productId}
order by br.score ${dto.sortOrder}
order by br.created_time ${dto.sortOrder}
order by br.created_time desc
